#include <bits/stdc++.h>
using namespace std;
int n,ans;
string a,b;
int main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n;
	for(int i=1; i<=n; i++) {
		cin>>a;
		if(a.size()>b.size()){
			b=a;
			ans=i;
		}else if(a.size()==b.size()&&a>b){
			b=a;
			ans=i;
		}
	}
	cout<<ans<<"\n"<<b;
	return 0;
}
